jQuery.validator.setDefaults({highlight:function(n,t,i){n.type==="radio"?this.findByName(n.name).addClass(t).removeClass(i):($(n).addClass(t).removeClass(i),$(n).closest(".control-group").removeClass("success").addClass("error"))},unhighlight:function(n,t,i){n.type==="radio"?this.findByName(n.name).removeClass(t).addClass(i):($(n).removeClass(t).addClass(i),$(n).closest(".control-group").removeClass("error").addClass("success"))}})